// Demonstrating Security Properties
BEGIN SecurityProperties

 // Without security: State compromise reveals all
 FUNCTION InsecurePRNG_Compromise(state, pastOutputs)
 // Knowing state, attacker can regenerate all past outputs
 attackerKnowledge ← state
 // Can also predict ALL future outputs
 futurePredictable ← TRUE
 RETURN attackerKnowledge, futurePredictable
 END FUNCTION

 // With forward security: Past outputs protected
 FUNCTION ForwardSecure_Compromise(currentState, pastOutputs)
 // Even with current state, cannot recover past outputs
 // Because outputs were generated before current state existed
 pastRecoverable ← FALSE
 futurePredictable ← TRUE // But future is compromised
 RETURN pastRecoverable
 END FUNCTION

 // With backward security: Seed not recoverable
 FUNCTION BackwardSecure_Compromise(currentState, seed)
 // Knowing current state, cannot determine original seed
 // Because transition function is one-way (computationally hard)
 seedRecoverable ← FALSE
 RETURN seedRecoverable
 END FUNCTION

 // Complete secure PRNG simulation
 FUNCTION DemonstrateSecurity(seed)
 // Generate sequence
 outputs ← GenerateSecureSequence(seed, 100)

 // Attack scenario 1: Intercept outputs only
 intercepted ← outputs[1:50]
 // Cannot predict outputs[51:100] - unpredictable

 // Attack scenario 2: Compromise state at position 50
 compromisedState ← stateAtPosition(50)
 // Forward secure: Cannot recover outputs[1:49]
 // Backward secure: Cannot recover seed

 RETURN "System demonstrates forward and backward security"
 END FUNCTION

END SecurityProperties
